import { FileUtils } from './FileUtils';
import { EventEmitter } from 'events';

export enum Type {
	NUMBER = 'NUMBER',
	BOOLEAN = 'BOOLEAN',
	STRING = 'STRING'
}

export type ValueProvider<T> = (...args: any[]) => (T | Promise<T>);

/**
 * Parses a boolean value
 * @param {string|boolean} input
 * @return {boolean}
 */
function getBoolean(input: string|boolean): boolean {
	if (typeof input === 'boolean') {
		return input;
	}
	else if (typeof input === 'string') {
		return !!JSON.parse(input.toLowerCase());
	}
	else {
		throw new Error(`Can't parse boolean '${input}'`);
	}
}

/**
 * @class TestConfiguration
 */
export class TestConfiguration extends EventEmitter {

	private _data: any;
	private _testConfig: any;
	private _hasTestData = false;

	constructor(public namespace: string) {
		super();
	}

	/**
	 * Initializes test configuration from test file (if it exists)
	 * Should be called after all value providers have been provided
	 * @param {string} [pathToTestConfig] Path to test config file
	 * @return {Promise<boolean>} True if test configuration loaded, false otherwise
	 */
	async init(pathToTestConfig: string): Promise<boolean> {
		let data: any;
		try {
			data = await FileUtils.readFile(pathToTestConfig);
		} catch (error) {
			// Skipping file read error (since file might not exist)
		}

		if (data) {
			try {
				data = JSON.parse(data);
			}
			catch (error) {
				throw new Error(`Error parsing test config '${pathToTestConfig}': ${error}`);
			}
			// If the test data object is enabled and has our namespace
			const enabled = getBoolean(data.enabled);
			if (enabled && data[this.namespace]) {
				this._data = data[this.namespace];

				// Verify test values
				// TOFIX check if test names are expected
				this._hasTestData = true;
				return true;
			}
		}

		if (!this._data) {
			this._data = {};
			return false;
		}
	}

	/**
	 * Returns true if this class has loaded a valid test configuration
	 * and that it is enabled
	 * @return {boolean}
	 */
	hasEnabledTestConfig(): boolean {
		return this._hasTestData;
	}

	/**
	 * Returns true if this class has an overriding test configuration
	 * @return {boolean}
	 */
	hasOverridingTestConfig(): boolean {
		return !!this._testConfig;
	}

	/**
	 * Clears the overriding test config
	 */
	clearOverridingTestConfig() {
		this._testConfig = null;
	}

	/**
	 * Sets the overriding test config. If null then test config is disabled
	 * @param {Object} testConfig Null to disable
	 */
	setOverridingTestConfig(testConfig: any) {
		this._testConfig = testConfig;

		if (testConfig) {
			// Verify values
			// TOFIX check if test names are expected

		}
	}

	/**
	 * Waits for event emitted on this object
	 * @param {string} name
	 * @return {Promise<void>}
	 */
	async waitForEvent(name: string): Promise<void> {
		return new Promise<void>( resolve => {
			this.once(name, () => resolve());
		});
	}

	/**
	 * A number value getter
	 * @param {string} name
	 * @param {function} [provider] A provider of the real value in case it doesn't exist in test config
	 * @return {Promise<number|null>}
	 */
	async getNumberFromTestConfig(name: string, provider?: ValueProvider<number>): Promise<number> {
		const val = await this._getFromTestConfig(name, Type.NUMBER);
		if (val !== null) {
			return parseFloat(val);
		}
		else if (provider) {
			return Promise.resolve(provider());
		}
		else {
			return null;
		}
	}

	/**
	 * A string value getter
	 * @param {string} name
	 * @param {function} [provider] A provider of the real value in case it doesn't exist in test config
	 * @return {Promise<string|null>}
	 */
	async getStringFromTestConfig(name: string, provider?: ValueProvider<string>): Promise<string> {
		const val = await this._getFromTestConfig(name, Type.STRING);
		if (val !== null) {
			return (typeof val === 'string') ? val : ('' + val);
		}
		else if (provider) {
			return Promise.resolve(provider());
		}
		else {
			return null;
		}
	}

	/**
	 * A boolean value getter
	 * @param {string} name
	 * @param {function} [provider] A provider of the real value in case it doesn't exist in test config
	 * @return {Promise<boolean|null>}
	 */
	async getBooleanFromTestConfig(name: string, provider?: ValueProvider<boolean>): Promise<boolean> {
		const val = await this._getFromTestConfig(name, Type.BOOLEAN);
		if (val !== null) {
			return getBoolean(val);
		}
		else if (provider) {
			return Promise.resolve(provider());
		}
		else {
			return null;
		}
	}

	/**
	 * A generic value getter
	 * @param {string} name
	 * @param {Type} type
	 * @return {Promise<any>}
	 * @private
	 */
	private async _getFromTestConfig(name: string, type: Type): Promise<any> {
		if (!this._data) {
			throw new Error(`Test configuration '${this.namespace}' is not initialized`);
		}

		// TOFIX check if value name is expected and type thereof

		// If we find the data in the overriding test file
		if (this._testConfig && this._testConfig[name] !== undefined) {
			return this._testConfig[name];
		}
		// If we find the data in our test file
		else if (this._data[name] !== undefined) {
			return this._data[name];
		}

		return null;
	}
}
