/**
 * Manage a set of objects with ids and a cache
 * @type {[type]}
 */
export class CacheManager<ObjectType, IDType, CacheType> {

    public idToObject:Map<IDType, ObjectType> = new Map<IDType, ObjectType>();
    public objectToId:Map<ObjectType, IDType> = new Map<ObjectType, IDType>();
    public idToCache:Map<IDType, CacheType> = new Map<IDType, CacheType>();
    public cache:Map<CacheType, Set<ObjectType>> = new  Map<CacheType, Set<ObjectType>>();

    public addObjectToCache(obj:ObjectType, id:IDType, cache:CacheType) {
        if(!this.cache.has(cache)) {
            this.cache.set(cache, new Set<ObjectType>());
        }
        this.cache.get(cache).add(obj);
        this.idToObject.set(id, obj);
        this.objectToId.set(obj, id);
        this.idToCache.set(id, cache);
    }

    public getById(id:IDType):ObjectType {
        return this.idToObject.get(id);
    }

    public removeCache(cache:CacheType):ObjectType[] {
        const cacheSet:Set<ObjectType> = this.cache.get(cache);
        if(!cacheSet) {
            return [];
        }
        this.cache.delete(cache);
        const objects:ObjectType[] = [];
        cacheSet.forEach((obj:ObjectType) => {
            objects.push(obj);
            this.removeByObj(obj);
        });
        return objects;
    }

    /**
     * Removes both the object and the id from cache, but does not
     * delete an entire cache
     * @param {IDType} id 
     */
    public removeById(id:IDType):ObjectType {
        const obj:ObjectType = this.idToObject.get(id);
        this.objectToId.delete(obj);
        this.idToObject.delete(id);
        let cacheKey = this.idToCache.get(id);
        this.idToCache.delete(id);

        if(cacheKey !== undefined){ //might be undefined if obj wasn't cached
            let setForCache = this.cache.get(cacheKey);
            setForCache.delete(obj);
            if(setForCache.size === 0){
                this.cache.delete(cacheKey);
            }
        }

        return obj;
    }

    /**
     * This removes the object and id from cache, but does not delete
     * an entire cache
     * @param obj 
     */
    public removeByObj(obj:ObjectType) {
        const id:IDType = this.objectToId.get(obj);
        this.objectToId.delete(obj);
        this.idToObject.delete(id);
        let cacheKey = this.idToCache.get(id);
        this.idToCache.delete(id);

        if(cacheKey !== undefined){ //might be undefined if obj wasn't cached
            let setForCache = this.cache.get(cacheKey);
            if(setForCache !== undefined) { //can be undefined if we're called from removeCache
                setForCache.delete(obj);
                if (setForCache.size === 0) {
                    this.cache.delete(cacheKey);
                }
            }
        }
    }
}
