import parentLog from '../log';
const log = parentLog.createChild('PromiseUtils');

export interface Callback<T> {
    (error?: any, data?: T): any;
}

export interface NonStandardCallback<T> {
    (data?: T): any;
}


export class PromiseUtils {

    /**
     * Installs a global handler for unhandled rejected promises
     * Makes sure to only install one instance.
     */
    static catchUnhandledRejection() {
        let gl: any = global;

        if (!gl._hasInstalledUncaughtHandler) {
            process.on('unhandledRejection', (reason, p) => {
                log.error(`Unhandled Rejection at: Promise '${JSON.stringify(p)}'`);
                if (reason instanceof Error) {
                    log.error(`  message: ${reason.message}`);
                    log.error(`  stack: ${reason.stack}`);
                }
                else {
                    log.error(reason);
                }
            });
            gl._hasInstalledUncaughtHandler = true;
        }
    }

    /**
     * Returns promise that succeeds when the first input promise succeeds
     * If all input promises fail, then the returned promise fails.
     * @param {Promise<T>[]} promises
     * @returns {Promise<T>}
     */
    static async firstToSucceed<T>(promises: Promise<T>[]): Promise<T> {
        return new Promise<T>( (res, rej) => {
            let errors = [];
            let errorCount = 0;

            for (let i = 0; i < promises.length; i++) {
                promises[i].then(res).catch( e => {
                    errors[i] = e;
                    errorCount++;
                    if (errorCount === promises.length) {
                        rej(errors);
                    }
                });
            }
        });
    }

    /**
     * A method that allows you to convert a 'callback' async function to
     * a promise async function. The only requirement is that the callback
     * signature must be of type (error: any, data?:any)
     * @param {Function.<Callback>} func
     * @returns {Promise<any>}
     */
    static promisify<T>(func: (cb: Callback<T>) => any): Promise<T>;
    /**
     * A method that allows you to convert a 'callback' async function to
     * a promise async function. The only requirement is that the callback
     * signature must be of type (data?:any)
     * @param {Function.<NonStandardCallback>} func
     * @param {boolean} [firstParamError=true] Must be set to false if first argument in callback
     * will not be an error message but the data itself
     * @returns {Promise<any>}
     */
    static promisify<T>(func: (cb: NonStandardCallback<T>) => any, firstParamError:boolean): Promise<T>;
    static promisify<T>(func: (cb: Callback<T>|NonStandardCallback<T>) => any, firstParamError=true): Promise<T> {
        return new Promise<T>( (resolve, reject) => {
            func((error, result) => {
                if (firstParamError) {
                    if (error) {
                        reject(error);
                    }
                    else {
                        resolve(result);
                    }
                }
                else {
                    // In this case it is assumed that the data is in the first argument
                    if (result) {
                        log.warn(`Data in second argument ignored`);
                    }
                    resolve(error);
                }
            });
        });
    }

    /**
     * A method that allows awaiting a promise safely without using try/catch
     * The return signature is an array that can be decontructed on use, and
     * has a similar shape to a standard Node.js callback
     * @param  {Promise<T>} func
     * @returns {Promise<[any, T]>}
     */
    static to<T>(promise: Promise<T>): Promise<[Error|string, T]> {
        return promise
            .then(data => [null, data] as [Error|string, T])
            .catch(err => [err, null] as [Error|string, T]);
    }

    /**
     * A method that combines PromiseUtils.promisify with PromiseUtils.to,
     * with one method call
     * @param  {[type]} PromiseUtils.promisify(func,firstParamError [description]
     * @return {[type]}                                             [description]
     */
    static promisifyTo<T>(func: (cb: Callback<T>) => any): Promise<[Error|string, T]>;
    static promisifyTo<T>(func: (cb: NonStandardCallback<T>) => any, firstParamError:boolean): Promise<[Error|string, T]>;
    static promisifyTo<T>(func: (cb: Callback<T>|NonStandardCallback<T>) => any, firstParamError=true): Promise<[Error|string, T]> {
        return PromiseUtils.to(PromiseUtils.promisify(func, firstParamError));
    }

    /**
     * Resolve only if the passed-in promise resolves before the timeout
     * Rejects with 'Timeout' if the timeout occurs before the promise resolves
     * Passes through the rejection from the promise if it rejects before the
     * timeout
     * @param  {Promise<T>} promise The promise to race against the timeout
     * @param  {number} timeoutMs Milliseconds before the timeout rejects the promise
     * @param  {string} [errorMessage] Error message to use on timeout reject
     * @return {Promise<T>} The new promise that rejects on timeout
     */
    static timeout<T>(promise: Promise<T>, timeoutMs: number, errorMessage?: string): Promise<T> {
        return new Promise<T>((resolve, reject) => {
            const timeoutHandle = setTimeout(() => {
                reject(new Error(errorMessage || `Timeout of ${timeoutMs}ms`));
            }, timeoutMs);
            promise
                .then(data => resolve(data))
                .catch(error => reject(error))
                .then(() => clearTimeout(timeoutHandle));
        });
    }
}
